#!/bin/bash

cat << EOF
module Klas.SPMM

// THIS FILE IS AUTOMATICALLY GENERATED BY A SCRIPT, DO NOT EDIT

#lang-pulse
open Kuiper
open Klas.SPMM.Inst

// One single u32 variant for the test
let spmm_u32 = inst u32 128sz 128sz 32sz

// A fixed-name f32 variant for the test and quick benching
let spmm_f32 = inst f32 512sz 512sz 64sz

EOF

# let spmm_u32 = inst u32 128sz 128sz 32sz
# let spmm_f32 = inst f32 128sz 128sz 32sz

# Tweak these lists to control which instances are generated
all_blockItemsX="16 32 64 128 256 512"
all_blockItemsK="16 32 64 128 256 512"
all_blockWidth="16 32 64 128 256 512"

for blockItemsK in $all_blockItemsK; do
  for blockItemsX in $all_blockItemsX; do
    for blockWidth in $all_blockWidth; do
      if [ $((blockItemsK % blockWidth)) -ne 0 ]; then continue; fi
      if [ $((blockItemsX % blockWidth)) -ne 0 ]; then continue; fi
      if [ $(( (blockItemsK / blockWidth) % 4 )) -ne 0 ]; then continue; fi
      if [ $(( (blockItemsX / blockWidth) % 4 )) -ne 0 ]; then continue; fi
      echo "let g_spmm_f32_${blockItemsK}x${blockItemsX}x${blockWidth} = inst f32 ${blockItemsK}sz ${blockItemsX}sz ${blockWidth}sz"
    done
  done
done
